import { useEffect, useMemo, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../api/axios";

const getTomorrowDateString = () => {
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const year = tomorrow.getFullYear();
  const month = String(tomorrow.getMonth() + 1).padStart(2, "0");
  const day = String(tomorrow.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
};

const formatDisplayTime = (time) => {
  if (!time) return "Select a session";
  const [hours, minutes] = time.split(":").map(Number);
  const suffix = hours >= 12 ? "PM" : "AM";
  const hour12 = hours % 12 || 12;
  return `${hour12}:${String(minutes).padStart(2, "0")} ${suffix}`;
};

export default function EditAppointment() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [appointment, setAppointment] = useState({
    lead: "",
    vehicle: "",
    appointmentType: "viewing",
    date: "",
    time: "",
    status: "scheduled",
    notes: "",
  });
  const [leads, setLeads] = useState([]);
  const [vehicles, setVehicles] = useState([]);
  const [availableSlots, setAvailableSlots] = useState([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true);
        const [apptRes, leadRes, vehicleRes] = await Promise.all([
          api.get(`/appointments/${id}`),
          api.get("/leads"),
          api.get("/vehicles"),
        ]);

        const a = apptRes.data;
        setAppointment({
          lead: a.lead?._id || a.lead || "",
          vehicle: a.vehicle?._id || a.vehicle || "",
          appointmentType: a.appointmentType || "viewing",
          date: a.date ? String(a.date).slice(0, 10) : "",
          time: a.time || "",
          status: a.status || "scheduled",
          notes: a.notes || "",
        });
        setLeads(Array.isArray(leadRes.data) ? leadRes.data : []);
        setVehicles(Array.isArray(vehicleRes.data) ? vehicleRes.data : []);
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load appointment");
        navigate("/appointments");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id, navigate]);

  useEffect(() => {
    const loadSlots = async () => {
      if (!appointment.date) {
        setAvailableSlots([]);
        return;
      }

      try {
        const res = await api.get(
          `/appointments/available-slots/${appointment.date}?excludeAppointmentId=${id}`
        );
        setAvailableSlots(res.data?.slots || []);
      } catch (err) {
        setAvailableSlots([]);
        setError(err.response?.data?.message || "Failed to load available sessions");
      }
    };

    loadSlots();
  }, [appointment.date, id]);

  const selectedLead = useMemo(
    () => leads.find((lead) => lead._id === appointment.lead),
    [leads, appointment.lead]
  );

  const handleChange = (e) => {
    const { name, value } = e.target;
    setAppointment((current) => ({
      ...current,
      [name]: value,
      ...(name === "date" ? { time: "" } : {}),
    }));
    setError("");
  };

  const submit = async (e) => {
    e.preventDefault();
    if (!appointment.date || !appointment.time) {
      setError("Please choose a valid future date and one available hourly session");
      return;
    }

    try {
      setSaving(true);
      setError("");
      await api.put(`/appointments/${id}`, appointment);
      navigate("/appointments");
    } catch (err) {
      setError(err.response?.data?.message || "Update failed");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Appointment</div>
          <div className="pageSub">
            Update this booking using hourly sessions from 9:00 AM to 5:00 PM
          </div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 880, margin: "32px auto" }}>
        {error ? (
          <div
            style={{
              marginBottom: 20,
              padding: 14,
              borderRadius: 12,
              backgroundColor: "#fef2f2",
              color: "#b91c1c",
              border: "1px solid rgba(185, 28, 28, 0.18)",
              fontWeight: 600,
            }}
          >
            {error}
          </div>
        ) : null}

        <form onSubmit={submit}>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))", gap: 18 }}>
            <div>
              <label className="label">Lead</label>
              <select name="lead" value={appointment.lead} onChange={handleChange} required className="select" disabled={loading || saving}>
                <option value="">Select Lead</option>
                {leads.map((lead) => (
                  <option key={lead._id} value={lead._id}>
                    {lead.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="label">Vehicle</label>
              <select name="vehicle" value={appointment.vehicle} onChange={handleChange} required className="select" disabled={loading || saving}>
                <option value="">Select Vehicle</option>
                {vehicles.map((vehicle) => (
                  <option key={vehicle._id} value={vehicle._id}>
                    {vehicle.brand} {vehicle.model || vehicle.type || ""} ({vehicle.year})
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="label">Appointment Type</label>
              <select name="appointmentType" value={appointment.appointmentType} onChange={handleChange} className="select" disabled={saving}>
                <option value="viewing">Viewing</option>
                <option value="test_drive">Test Drive</option>
                <option value="follow_up">Follow Up</option>
              </select>
            </div>

            <div>
              <label className="label">Status</label>
              <select name="status" value={appointment.status} onChange={handleChange} className="select" disabled={saving}>
                <option value="scheduled">Scheduled</option>
                <option value="completed">Completed</option>
                <option value="cancelled">Cancelled</option>
              </select>
            </div>
          </div>

          <div style={{ marginTop: 22 }}>
            <label className="label">Date</label>
            <input
              type="date"
              name="date"
              value={appointment.date}
              onChange={handleChange}
              required
              min={getTomorrowDateString()}
              className="input"
              disabled={saving}
            />
            <div style={{ fontSize: 12, color: "var(--text-light)", marginTop: 6 }}>
              Only future dates are allowed. Daily sessions run hourly from 9:00 AM to 5:00 PM.
            </div>
          </div>

          <div style={{ marginTop: 22 }}>
            <label className="label">Available Sessions</label>
            {appointment.date ? (
              availableSlots.length > 0 ? (
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))",
                    gap: 10,
                    marginTop: 8,
                  }}
                >
                  {availableSlots.map((slot) => {
                    const selected = appointment.time === slot.time;
                    const disabled = slot.availableStaffCount === 0;

                    return (
                      <button
                        key={slot.time}
                        type="button"
                        onClick={() => !disabled && setAppointment((current) => ({ ...current, time: slot.time }))}
                        disabled={disabled || saving}
                        className="btn"
                        style={{
                          padding: "12px 10px",
                          borderRadius: 14,
                          border: selected ? "1px solid #16202b" : "1px solid var(--border)",
                          background: selected ? "#16202b" : "#fff",
                          color: selected ? "#fff" : "var(--text)",
                          opacity: disabled ? 0.45 : 1,
                          cursor: disabled ? "not-allowed" : "pointer",
                        }}
                      >
                        <div style={{ fontWeight: 700 }}>{formatDisplayTime(slot.time)}</div>
                        <div style={{ fontSize: 12, marginTop: 4 }}>
                          {slot.availableStaffCount} staff available
                        </div>
                      </button>
                    );
                  })}
                </div>
              ) : (
                <div style={{ marginTop: 8, color: "var(--text-light)" }}>No sessions available on this date.</div>
              )
            ) : (
              <div style={{ marginTop: 8, color: "var(--text-light)" }}>Select a date to see available sessions.</div>
            )}
          </div>

          <div style={{ marginTop: 22 }}>
            <label className="label">Notes</label>
            <textarea
              name="notes"
              value={appointment.notes}
              onChange={handleChange}
              rows={4}
              className="textarea"
              placeholder="Interaction notes"
              disabled={saving}
            />
          </div>

          <div
            style={{
              marginTop: 24,
              padding: 16,
              borderRadius: 14,
              background: "rgba(248, 244, 235, 0.95)",
              border: "1px solid var(--border)",
              color: "var(--text-secondary)",
            }}
          >
            <strong style={{ color: "var(--text)" }}>{selectedLead?.name || "Selected lead"}</strong>
            <span> will be scheduled for </span>
            <strong style={{ color: "var(--text)" }}>{formatDisplayTime(appointment.time)}</strong>
            <span> on </span>
            <strong style={{ color: "var(--text)" }}>{appointment.date || "a future date"}</strong>
            <span>.</span>
          </div>

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button type="submit" className="btn btnPrimary" disabled={saving}>
              {saving ? "Saving..." : "Save Changes"}
            </button>
            <button type="button" onClick={() => navigate("/appointments")} className="btn" disabled={saving}>
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
